var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"클리포트 게임에서 모습을 드러낸 최고 관리자. 그는 누구인가?","JPN":"クリフォトゲームで姿を現した最高管理者。彼は誰なのか？","ENG":"The Supreme Administrator reveals himself in the Qliphoth Game. Who is he?","TWN":"在逆卡巴拉遊戲中現身的最高管理者。他是誰？"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE"},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"전대미문의 사건. 클리포트 게임에서 소문만 무성했던 최고 관리자가 모습을 드러냈다.","JPN":"前代未聞の事件。クリフォトゲームで噂の最高管理者が姿を現した。","ENG":"In an unprecedented case, the rumored Supreme Administrator finally appears in the Qliphoth Game.","TWN":"前所未聞的事件。在逆卡巴拉遊戲中只聞其名的最高管理者現身。"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE"},{"id":"L5_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_NULL","text":{"KOREA":"최고 관리자……?","JPN":"最高管理者……？","ENG":"Supreme Administrator...?","TWN":"最高管理者……？"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"아는 사람이…… 아니었나요?","JPN":"知り合いじゃ……なかったんですか？","ENG":"Is he... someone you know?","TWN":"你不認識他嗎……？"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L9_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_NULL","text":{"KOREA":"대부분의 전대원들은 최고 관리자가 아닌 테라브레인의 선별로 차출된다.","JPN":"ほとんどの戦隊員は最高管理者ではなく、テラブレインの選別によって呼び出される。","ENG":"Most division members are selected by Terrabrain and not the Supreme Administrator.","TWN":"大部分隊員都是由特拉大腦篩選出來的，而不是最高管理者。"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L10_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_NULL","text":{"KOREA":"최고 관리자가 있다는 소문 정도나 들었지. 그 실체를 확인한 건 이번이 처음이야.","JPN":"最高管理者がいるという噂なら聞いている。だが、その実体を確認したのは今回が初めてだ。","ENG":"I've heard rumors that there was a Supreme Administrator, but it's my first time confirming that he really exists.","TWN":"我只是聽說過有最高管理者的傳聞，這次是第一次發現他是真實存在的。"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L12_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_NULL","text":{"KOREA":"코핀 컴퍼니라…… 여전히 의지를 이어가겠다는 건가.","JPN":"コフィンカンパニーか……今の時代でも、その意志を繋いでいくということか。","ENG":"Coffin Company...? So he still remains committed to carrying out the will, I see.","TWN":"科芬公司……所以他也在繼續前進嗎？"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NULL","text":{"KOREA":"정말 많은 것이 변했어요. 클리포트 게임에서 승리할 줄은…….","JPN":"本当に多くのものが変わりましたね。クリフォトゲームで勝利するとは……","ENG":"A lot has changed indeed. Who knew we'd win the Qliphoth Game...","TWN":"變化很大呢，沒想到會在逆卡巴拉遊戲中獲勝……"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NULL","text":{"KOREA":"하지만 어째서 세상은 평화로워지지 않은 걸까요?","JPN":"ですが、どうして世界は平和になっていないのでしょうか。","ENG":"But then, why hasn't the world found peace yet?","TWN":"但為什麼這個世界還是無法獲得和平呢？"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_NULL","text":{"KOREA":"게임에서 이긴다고 다가 아니라는 거겠지.","JPN":"ゲームで勝つことがすべてではないということだろう。","ENG":"Because winning the game is not everything.","TWN":"那是因為獲勝並不是全部。"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_NULL","text":{"KOREA":"그래도 이제껏 해내지 못한 일을 해냈다는 것이 중요하다.","JPN":"だが、今までできなかったことを成し遂げたということが重要だ。","ENG":"Still, what's important is that we have accomplished something that has never been done before.","TWN":"不過，重要的是我們已經完成至今未能完成的事。"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_NULL","text":{"KOREA":"동결되어 있던 사이에…… 정말 세상이 뒤집힌 셈이 됐군.","JPN":"凍結されていた間に……本当に世の中がひっくり返ったようだ。","ENG":"While I was frozen... the world really did turn upside down.","TWN":"在我被冰封的這段時間……世界真是有翻天覆地的改變。"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NULL","text":{"KOREA":"적어도 지금 당장 싸우러 나가진 않아도 되겠네요.","JPN":"少なくとも、今すぐ戦いに行かなくてもよさそうですね。","ENG":"I assume that I won't have to go out to fight immediately, at least.","TWN":"至少我們現在不需要立刻出去作戰。"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_NULL","text":{"KOREA":"지금은 정보와 지식을 습득해야 할 때다.","JPN":"今は情報と知識を習得する時だ。","ENG":"Right now, our priority lies in acquiring information and knowledge.","TWN":"現在，我們的任務是獲取資訊和更多知識。"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L22_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_NULL","text":{"KOREA":"여러 곳의 정보도 얻을 겸…… 그래. 가이드나 해보는 건 어떤가?","JPN":"いろんな場所の情報も入手するついでに……そうだ。ガイドでもやってみるのはどうだ？","ENG":"And to obtain information from various places... Yes. How about we become guides?","TWN":"說到這個……這樣吧？試試看當導遊怎麼樣？"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L23_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"가, 가이드요? 가이드는 역사나 지리에 해박해야 해요. 두 분은 좀 힘들지 않을까요?","JPN":"が、ガイドですか？　ガイドは歴史や地理に詳しくないとダメですよ。二人にはちょっと無理じゃないでしょうか？","ENG":"G-guides? But guides have to be extremely knowledgeable on history and geography. Won't it be too difficult for you two?","TWN":"導，導遊嗎？導遊需要對歷史和地理非常了解。你們兩個可能有點困難吧？"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L24_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"무, 물론 요즘은 카운터 가이드들이 더 선호되는 트렌드이긴 하지만…….","JPN":"も、もちろん最近はカウンターガイドがもっと好まれてはいるんですけど……","ENG":"I-I mean, there is a trend going on with Counter guides being more preferred, but...","TWN":"雖然最近制裁者導遊更受歡迎……"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"시, 싫다는 건 아니에요! 저, 저는 오히려 하고 싶다고 할까…….","JPN":"い、嫌ってわけじゃないんですよ！　わ、私はむしろやりたいっていうか……","ENG":"I-I'm not saying I don't like the idea! I-I would actually love to do it...","TWN":"不，不是說不想要！相反我很喜歡……"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_NULL","text":{"KOREA":"카운터 가이드가 선호된다는 걸로 충분하다. 나머지는 몸으로 배우면 돼.","JPN":"カウンターガイドが好まれているということで十分だ。後は体で覚えればいい。","ENG":"If Counter guides are preferred, that's enough for me. The rest, we'll learn as we go.","TWN":"那就夠了，其他的我們走一步算一步吧。"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L28_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_NULL","text":{"KOREA":"아샤, 라비와 어렸을 적부터 여행을 자주 다녔다고 하지 않았나?","JPN":"アーシャ、ラビと幼い頃からよく旅をしていたと言ってなかったか？","ENG":"Asha, didn't you say you frequently traveled with Ravi when you were young?","TWN":"阿莎，你不是從小就經常和拉維一起旅行嗎？"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_NULL","text":{"KOREA":"네가 이 일에 적격이라고 생각했는데.","JPN":"君にうってつけの仕事だと思ったのだか。","ENG":"I think you're a perfect fit for this job.","TWN":"我認為你會很適合這份工作。"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"저, 적격이요? 그럼요! 뭐부터 알려드릴까요?","JPN":"そ、そうですか？　もちろんです！　何から始めましょうか？","ENG":"P-perfect fit? Of course! What should I teach you first?","TWN":"我……很合適嗎？那好！需要我告訴你什麼？"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"침식체와 최초 조우? 대정화 전쟁? 대균열 관측? 브리트라 요격전?","JPN":"侵食体との初遭遇？　大浄化戦争？　大亀裂の観測？　ブリトラ迎撃戦？","ENG":"The first encounter with C.O.s? The Grand Purification War? The observation of Grand Dimension Crevice? The Britra Interception?","TWN":"與侵蝕體的首次遭遇？大淨化作戰？對大峽谷的觀測結果？還是佈雷特攔截戰？"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L34_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_NULL","text":{"KOREA":"……아니, 나한테 그걸 알려줄 필요는 없다. 따로 찾아보도록 하지.","JPN":"……いや、私にそんなことを教える必要はない。各々で調べてみるとしよう。","ENG":"...No. There's no need for you to tell me about them. I'll research them myself.","TWN":"……不，不需要告訴我那些。我會自己去查的。"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L36_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_NULL","text":{"KOREA":"우선, 네 명의로 사무소를 차릴 계획인데, 괜찮나?","JPN":"まず、君の名義で事務所を開業するつもりだが、大丈夫か？","ENG":"First, I'd like to open an office under your name. Would that be all right?","TWN":"首先，我計畫以你的名義開一家公司，可以嗎？"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L37_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"사무소요?","JPN":"事務所ですか？","ENG":"An office?","TWN":"公司嗎？"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"저는 돈도 없고…… 아마 신용 등급도…….","JPN":"私お金もないですし……たぶん信用スコアも……","ENG":"But I have no money... and my credit score is also...","TWN":"我既沒錢……信用評等也……"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_NULL","text":{"KOREA":"돈이야 어떻게든 벌면 돼. 세상에 널린 게 이터니움인데.","JPN":"お金はなんとか稼げばいい。この世にはエタニウムが溢れている。","ENG":"We'll earn money. The world is scattered with Eternium.","TWN":"錢去賺就有，世界上到處都是永恆之金。"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_NULL","text":{"KOREA":"라비 부전대장은 나에게 널 부탁했다. 즉, 너와 우리는 떼어놓을 수 없는 사이라고 할 수 있지.","JPN":"私はラビ副戦隊長から君のことを託された。つまり、君と私たちは離れられない関係だと言えるだろう。","ENG":"Deputy Commander Ravi asked me to take care of you. In other words, you can say that we are inseparable.","TWN":"既然拉維把你託付給我，也就是說，你和我現在是一體的。"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_NULL","text":{"KOREA":"너는 우릴 부양해야 한다.","JPN":"君は私たちのことを養わなければならない。","ENG":"You must support us.","TWN":"你必須養活我們。"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_TADA2"},{"id":"L43_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_NULL","text":{"KOREA":"이제 너는 홀몸이 아니라고.","JPN":"君はもう一人ではないのだ。","ENG":"You are not alone anymore.","TWN":"你已經不再是一個人。"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"이이익! 누구 맘대로 부양자로 만드는 거예요! 그리고 관계가 뒤집어졌잖아요!","JPN":"ううっ！　私はお二人の介護者ではありません！　それに、逆でしょう！","ENG":"Eeeek! Why am I the adult here?! It should be you!","TWN":"欸欸！怎麼變成我養你！這不對吧！"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"날 부탁한다면서! 뻔뻔해!","JPN":"私のことを託されたって言ってたじゃないですか！　図々しいです！","ENG":"Father asked you to take care of me! Have you no shame?!","TWN":"還說什麼託付！真是厚臉皮！"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NULL","text":{"KOREA":"그래도 아샤, 기쁜 표정을 숨기지는 않네요.","JPN":"ですがアーシャ、顔は嬉しそうですね。","ENG":"And yet, we see that you can't stop smiling, Asha.","TWN":"不過阿莎，你笑得很開心呢。"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NULL","text":{"KOREA":"수리야 님은…… 그 사건에 대해 알아볼 생각이시죠?","JPN":"スーリヤ様は……あの事件のことを調べるおつもりなのですね？","ENG":"Miss Surya... you are thinking of finding out about that incident, aren't you?","TWN":"蘇利亞……你是打算調查那件事嗎？"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_NULL","text":{"KOREA":"그래. 아닐라. 분명 그 임무에서 어떤 변수가 작용한 게 분명해.","JPN":"そうだ、アニラ。きっとその任務で、何らかの変数が作用したのだ。","ENG":"Yes, Anila. I'm certain that there must have been some variable at play during the mission.","TWN":"沒錯，雅妮拉。那個任務中肯定有某些變數在起作用。"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_NULL","text":{"KOREA":"단순하게 계산이 빗나갔다고 생각하지 않아. 무언가의 개입이 있었을 것이다.","JPN":"単に計算が外れたとは思えない。何かが介入したに違いない。","ENG":"I don't think the calculations were off. Something must have interfered.","TWN":"我不認為只是簡單的計算錯誤。一定是有什麼東西介入。"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_NULL","text":{"KOREA":"세상이 다시 한번 바뀌려는 지금, 우리는 주도적으로 정보를 수집해야 해.","JPN":"もう一度世界が変わろうとしている今、私たちは積極的に情報を収集しなければならない。","ENG":"And now that the world is about to change once again, we must actively gather information.","TWN":"世界即將再次改變，我們必須主動收集情報。"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_NULL","text":{"KOREA":"용병보다는 가이드로 일하는 편이 좀 더 움직이기 편하지 않을까?","JPN":"傭兵よりはガイドの仕事がもっと動きやすいのではないか？","ENG":"Plus, wouldn't it be easier to move around as a guide than as a mercenary?","TWN":"比起當雇傭兵，當導遊會更方便行動吧？"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_NULL","text":{"KOREA":"듣자 하니 용병들은 이면 세계도 자주 들락거린다는데, 그것보다는 낫겠지.","JPN":"傭兵たちは裏世界にもよく出入りすると聞いたが、それよりはましだろう。","ENG":"From what I hear, mercenaries frequent the Counterside, so this should probably be better than that.","TWN":"聽說傭兵們經常出入異界，導遊應該比他們好一些吧。"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"뭐, 이면 세계를 관광지 삼는 곳은 없을테니까요. 조금은 설렐지도 모르겠네요.","JPN":"まあ、裏世界を観光地にしてるところはないでしょうからね。ちょっとはワクワクするかもしれません。","ENG":"Well, no one really visits the Counterside as a tourist destination. But that does excite me a little.","TWN":"嗯，畢竟沒有人會去異界旅遊。不過這麼想還是有些興奮呢。"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_NULL","text":{"KOREA":"이유를 하나 더 붙이자면 바뀐 세상을 여기저기 둘러보고 싶기도 해.","JPN":"もう一つ理由をつけるとすると、変わった世界をあちこち見て回りたい。","ENG":"Another reason is that I want to go around the world and see how it has changed.","TWN":"再加一個理由的話，我也想四處看看這個改變許多的世界。"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_NULL","text":{"KOREA":"맛있는 것도 잔뜩 먹고, 재밌는 곳도 잔뜩 구경하는 맛을 느껴보고 싶거든.","JPN":"美味しいものもたくさん食べて、興味深い場所もたくさん見物してみたいんだ。","ENG":"I want to experience it by eating delicious dishes and seeing landmarks.","TWN":"我想要品嚐許多獨特的地方美食，還要盡情遊覽有趣的地方。"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"결국 놀러 다니고 싶다는 거였잖아!","JPN":"単に遊びたいだけじゃないですか！","ENG":"You just want to play!","TWN":"結果就是你想出去玩嘛！"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L13_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NULL","text":{"KOREA":"이해해주세요. 전대장님은 한번도 이렇게 놀아본 적이 없으시거든요.","JPN":"理解してあげてください。戦隊長は一度もこんなふうに遊んだことがないのですから。","ENG":"Please understand. Commander has never had a chance to have fun.","TWN":"呵呵呵，請體諒一下，因為戰隊長從來沒有出去玩過。"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L18_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_NULL","text":{"KOREA":"아닐라. 한 가지 묻고 싶은 게 있다.","JPN":"アニラ、一つ聞いてもいいか？","ENG":"Anila, I have a question for you.","TWN":"雅妮拉，我有個問題想單獨問你。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NULL","text":{"KOREA":"뭔가요? 전대장 님이 궁금하신 거라면 뭐든지 대답할게요!","JPN":"なんですか？　戦隊長が気になっていることならなんでも答えます！","ENG":"What is it? I'll answer anything you're curious about, Commander!","TWN":"什麼事？戰隊長的話，什麼都可以問！"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_NULL","text":{"KOREA":"그 오랜 시간 동안 어떻게 바루나스트라의 내부에서 생존할 수 있었지?","JPN":"その長い間、どうやってヴァルナストラの内部で生存することができたのだ？","ENG":"How were you able to survive within Varunastra for all this time?","TWN":"那段漫長的時間裡，你是怎麼在伐樓拿之艦內生存下來的？"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NULL","text":{"KOREA":"네?","JPN":"はい？","ENG":"Excuse me?","TWN":"嗯……？"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_NULL","text":{"KOREA":"아무리 강한 카운터라고 해도 침식파에 많은 시간 노출된다면 침식을 피할 수 없어.","JPN":"いくら強いカウンターであっても、侵食波に長時間露出されたら侵食を避けられない。","ENG":"No matter how strong Counters are, they cannot avoid being Corrupted when exposed to Corruption rays for long periods.","TWN":"即使是再強的制裁者，長時間暴露在侵蝕波中也無法避免被侵蝕。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"WIND_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L28_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_NULL","text":{"KOREA":"네 도플갱어들이 우후죽순 나타났다는 것은 그만큼 많은 시간이 흘렀다는 소리야.","JPN":"君のドッペルゲンガーが大勢現われたということは、それほど時間が流れたということだ。","ENG":"The fact that your Doppelgangers appeared in droves means that a lot of time has passed.","TWN":"出現那麼多你的二重身，就表示已經經過很長一段時間。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WIND_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L29_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_NULL","text":{"KOREA":"하지만 너는 그 어떤 침식의 징후도 나타나지 않았지.","JPN":"だが君からは侵食の兆候がまったく見えなかった。","ENG":"Yet, you don't show any signs of Corruption.","TWN":"但你沒有表現出任何被侵蝕的跡象。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WIND_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L30_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_NULL","text":{"KOREA":"무슨 일이 있었던 거지? 솔직하게 말해주면 좋겠군.","JPN":"何があったんだ？　素直に話してほしい。","ENG":"What happened? And I wish you to be honest with me.","TWN":"這是怎麼回事？你老實說出來吧。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WIND_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L32_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NULL","text":{"KOREA":"계약을…… 맺었어요. 덕분에 기억을 일부 돌려받고, 그 속에서 침식되지 않을 수 있었죠.","JPN":"契約を……しました。そのおかげで記憶を一部取り戻して、あの中で侵食されずにいられたのです。","ENG":"I... made a contract. Thanks to that, I was able to retrieve some of my memories and not get Corrupted inside.","TWN":"我……簽下一份契約。多虧如此，我才能找回一部分記憶，並且沒有被侵蝕。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_NULL","text":{"KOREA":"계약? 도대체 누가…….","JPN":"契約？　いったい誰と……","ENG":"A contract? With whom...?","TWN":"契約？到底是誰……"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NULL","text":{"KOREA":"누군가가 전대장님과의 약속을 반드시 지켜야 한다고 저에게 속삭였어요.","JPN":"誰かが私に必ず戦隊長との約束を守るようにと囁いたのです。","ENG":"Someone kept whispering to me that I must keep my promise with you, Commander.","TWN":"有個聲音悄悄告訴我，一定要遵守和戰隊長的約定。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L36_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NULL","text":{"KOREA":"저에게 전대장님이 돌아가신 수많은 미래를 보여주면서…….","JPN":"私に戦隊長が亡くなった数多くの未来を見せつけて……","ENG":"The being showed me countless versions of the future where you were dead...","TWN":"那個人給我看到無數個沒有你的未來……"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NULL","text":{"KOREA":"제가 여기서 살아남는 것이 전대장님이 살 수 있는 유일한 방법이라고 했거든요.","JPN":"私がここで生き残るのが戦隊長が生存する唯一の方法だと言っていました。","ENG":"It said the only way for you to live was for me to survive.","TWN":"還說我在那裡活下來，是戰隊長唯一能活下去的辦法。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};